module audio_mixer (
    input wire clk,
    input wire [15:0] audio_A,
    input wire [15:0] audio_B,
    input wire select,
    output reg [15:0] output_audio
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (select)
            output_audio <= audio_B;
        else
            output_audio <= audio_A;
    end
endmodule
